import { Injectable, signal } from '@angular/core';
import { ActionEvidenceDTO, ActionConsultationDTO, ComplianceProfileOption } from './action.models';

@Injectable()
export class ActionCaptureState {
  readonly actionId = signal<string>(crypto.randomUUID());
  readonly evidence = signal<ActionEvidenceDTO[]>([]);
  readonly consultations = signal<ActionConsultationDTO[]>([]);
  readonly complianceProfileOptions = signal<ComplianceProfileOption[]>([]);
}

// ✓ CORRECT — component-scoped, no providedIn
@Injectable()
export class ActionCaptureState {
  readonly evidence = signal<ActionEvidenceDTO[]>([]);
}

// ✗ WRONG — root-scoped, shared across all instances
@Injectable({ providedIn: 'root' })
export class ActionCaptureState {
  readonly evidence = signal<ActionEvidenceDTO[]>([]);
}

// ✗ WRONG — BehaviorSubject instead of signal (violates ADR-0006)
@Injectable()
export class ActionCaptureState {
  readonly evidence$ = new BehaviorSubject<ActionEvidenceDTO[]>([]);
}

// ✗ WRONG — plain mutable property, no reactivity
@Injectable()
export class ActionCaptureState {
  evidence: ActionEvidenceDTO[] = [];
}

// ✗ WRONG — form fields in state service (these stay local on the component)
@Injectable()
export class ActionCaptureState {
  readonly name = signal('');           // ✗ form field
  readonly loading = signal(false);     // ✗ lifecycle state
  readonly evidence = signal<ActionEvidenceDTO[]>([]);  // ✓ child collection
}

@Component({
  selector: 'app-action-capture',
  standalone: true,
  imports: [
    DatePipe, FormsModule, RouterLink, RouterOutlet,
    TextFieldComponent, CapturePageTitleComponent,
    ActionEvidenceListComponent, ActionConsultationListComponent,
  ],
  providers: [ActionCaptureState],  // Fresh instance per mount
  templateUrl: './action-capture.component.html',
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class ActionCaptureComponent {
  private readonly router = inject(Router);
  private readonly actionService = inject(ActionService);
  private readonly state = inject(ActionCaptureState);

  id = input<string>();  // Bound from route param via withComponentInputBinding()

  // --- Aggregate children: delegated to state so child routes access them ---
  evidence = this.state.evidence;
  consultations = this.state.consultations;
  complianceProfileOptions = this.state.complianceProfileOptions;

  // --- Server ID tracking for child diffing on save ---
  private serverEvidenceIds = new Set<string>();
  private serverConsultationIds = new Set<string>();

  /** Whether a child route (evidence/consultation capture) is active */
  childActive = signal(false);

  // ... form signals, validation, effects (see capture-page.md)
}

private async loadAction(id: string): Promise<void> {
  this.loading.set(true);
  this.errorMessage.set('');

  try {
    const dto = await this.actionService.get(id);

    // Populate local form signals
    this.name.set(dto.name);
    this.slug.set(dto.slug);

    // Populate state service (child routes access these)
    this.state.actionId.set(dto.id);
    this.state.evidence.set(dto.evidence);
    this.state.consultations.set(dto.consultations);

    // Snapshot server IDs for diffing on save
    this.serverEvidenceIds = new Set(dto.evidence.map(c => c.id));
    this.serverConsultationIds = new Set(dto.consultations.map(c => c.id));

    // Load lookup data for child routes (non-critical — fail silently)
    try {
      const types = await this.actionService.getComplianceProfileOptions(dto.slug);
      this.state.complianceProfileOptions.set(types);
    } catch {
      // Consultation capture will show no compliance profile options
    }
  } catch {
    this.errorMessage.set(await firstValueFrom(this.translate.get('actions.capture.loadError')));
  } finally {
    this.loading.set(false);
  }
}

async onSave(): Promise<void> {
  if (!this.isFormValid()) return;
  this.saving.set(true);
  this.errorMessage.set('');

  try {
    // Diff children: server IDs stay, temp UUIDs become EMPTY_GUID
    const evidence = this.evidence().map(c => ({
      ...c,
      id: this.serverEvidenceIds.has(c.id) ? c.id : EMPTY_GUID,
    }));
    const consultations = this.consultations().map(c => ({
      ...c,
      id: this.serverConsultationIds.has(c.id) ? c.id : EMPTY_GUID,
    }));

    const request: SaveActionRequest = {
      id: this.isEditMode() ? this.id()! : EMPTY_GUID,
      name: this.name().trim(),
      slug: this.slug().trim(),
      evidence,
      consultations,
    };

    const result = await this.actionService.save(request);

    if (this.isEditMode()) {
      await this.loadAction(this.id()!);  // Reload to show server state
    } else {
      this.router.navigate(['/admin/actions', result.id]);  // Navigate to edit URL
    }
  } catch (err: unknown) {
    const msg = (err as { error?: { errors?: { message?: string }[] } })
      ?.error?.errors?.[0]?.message ?? await firstValueFrom(this.translate.get('actions.capture.saveError'));
    this.errorMessage.set(msg);
  } finally {
    this.saving.set(false);
  }
}

import { ChangeDetectionStrategy, Component, computed, effect, inject, input, signal } from '@angular/core';
import { FormsModule } from '@angular/forms';
import { Router, ActivatedRoute } from '@angular/router';
import { TextFieldComponent, CapturePageTitleComponent } from '@nxgn-solutions/ui';

import { EnumDTO } from '@app/core/models/enum-dto';
import { ActionEvidenceDTO } from './action.models';
import { ActionCaptureState } from './action-capture.state';

const CLIENT_ID_REGEX = /^[a-z][a-z0-9._-]*$/;

@Component({
  selector: 'app-action-evidence-capture',
  standalone: true,
  imports: [FormsModule, TextFieldComponent, CapturePageTitleComponent],
  // NOTE: No providers — uses parent's ActionCaptureState
  template: `
    <nxgn-capture-page-title
      title="Evidence"
      [newRecord]="isNew()"
      [isValid]="isFormValid()"
      addPrefix="New"
      (save)="onConfirm()"
      (cancel)="onCancel()"
    />

    <div class="card">
      <div class="card-body">
        <div class="row g-3">
          <div class="col-md-6">
            <nxgn-text-field
              label="Evidence ID"
              placeholder="e.g. my-app.web"
              [(value)]="evidenceId"
              [disabled]="!isNew()"
            />
            @if (duplicateEvidenceId()) {
              <small class="form-text text-danger">
                This Evidence ID is already in use.
              </small>
            }
          </div>
          <div class="col-md-6">
            <nxgn-text-field
              label="Display Name"
              placeholder="e.g. My Action Web Evidence"
              [(value)]="displayName"
            />
          </div>
          <!-- ... additional fields (evidence type, kind, grant types, etc.) -->
        </div>
      </div>
    </div>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class ActionEvidenceCaptureComponent {
  private readonly router = inject(Router);
  private readonly route = inject(ActivatedRoute);
  private readonly state = inject(ActionCaptureState);

  /** Route param — undefined for 'evidence/new', UUID for 'evidence/:evidenceRef' */
  evidenceRef = input<string>();

  isNew = computed(() => !this.evidenceRef());

  // Form signals
  fileName = signal('');
  description = signal('');
  evidenceType = signal<EnumDTO | null>(null);

  /** ID for new records (generated once per component mount) */
  private newRecordId = crypto.randomUUID();

  // --- Duplicate detection from state ---

  /** Existing file names for duplicate detection (excludes the one being edited) */
  private existingFileNames = computed(() =>
    this.state.evidence()
      .filter(c => c.id !== this.evidenceRef())
      .map(c => c.fileName)
  );

  duplicateFileName = computed(() => {
    const name = this.fileName().trim();
    return name.length > 0 && this.existingFileNames().some(
      existing => existing.toLowerCase() === name.toLowerCase()
    );
  });

  isFormValid = computed(() => {
    const name = this.fileName().trim();
    const desc = this.description().trim();
    return (
      name.length > 0 && name.length <= 255 &&
      !this.duplicateFileName() &&
      desc.length <= 1000
    );
  });

  constructor() {
    // Populate form from state when editing an existing evidence
    effect(() => {
      const ref = this.evidenceRef();
      if (!ref) return;

      const existing = this.state.evidence().find(c => c.id === ref);
      if (!existing) return;

      this.fileName.set(existing.fileName);
      this.description.set(existing.description ?? '');
      this.evidenceType.set(existing.evidenceType);
    });
  }

  // --- Save: update parent's collection signal ---

  onConfirm(): void {
    if (!this.isFormValid()) return;

    const evidence: ActionEvidenceDTO = {
      id: this.evidenceRef() ?? this.newRecordId,  // Temp UUID for new items
      actionId: this.state.actionId(),
      fileName: this.fileName().trim(),
      description: this.description().trim() || null,
      evidenceType: this.evidenceType()!,
      status: { id: 0, name: 'Pending' },
      fileUrl: '',  // Set by upload flow
      uploadedDate: new Date().toISOString(),
    };

    if (this.isNew()) {
      // Append to parent's collection
      this.state.evidence.update(list => [...list, evidence]);
    } else {
      // Replace in parent's collection (preserve status from existing)
      const existing = this.state.evidence().find(c => c.id === this.evidenceRef());
      if (existing) evidence.status = existing.status;
      this.state.evidence.update(list => list.map(c => c.id === evidence.id ? evidence : c));
    }

    this.navigateBack();
  }

  onCancel(): void {
    this.navigateBack();
  }

  private navigateBack(): void {
    const id = this.route.parent?.snapshot.params['id'];
    this.router.navigate(['/admin/actions', id ?? 'new']);
  }
}

